type TextEditor struct {
    editor *list.List
    cursor *list.Element
}

func Constructor() TextEditor {
    editor := list.New()
    editor.PushBack(nil)
    return TextEditor{
        editor: editor,
        cursor: editor.Back(),
    }
}

func (this *TextEditor) AddText(text string) {
    for _, c := range text {
        this.editor.InsertBefore(byte(c), this.cursor)
    }
}

func (this *TextEditor) DeleteText(k int) int {
    count := 0
    for ; k > 0 && this.cursor != this.editor.Front(); k-- {
        this.editor.Remove(this.cursor.Prev())
        count++
    }
    return count
}

func (this *TextEditor) CursorLeft(k int) string {
    for ; k > 0 && this.cursor != this.editor.Front(); k-- {
        this.cursor = this.cursor.Prev()
    }
    head := this.cursor
    for i := 0; i < 10 && head != this.editor.Front(); i++ {
        head = head.Prev()
    }
    var ret []byte
    for ; head != this.cursor; head = head.Next() {
        ret = append(ret, head.Value.(byte))
    }
    return string(ret)
}

func (this *TextEditor) CursorRight(k int) string {
    for ; k > 0 && this.cursor != this.editor.Back(); k-- {
        this.cursor = this.cursor.Next()
    }
    head := this.cursor
    for i := 0; i < 10 && head != this.editor.Front(); i++ {
        head = head.Prev()
    }
    var ret []byte
    for ; head != this.cursor; head = head.Next() {
        ret = append(ret, head.Value.(byte))
    }
    return string(ret)
}
